export const code = async (inputs) => {
  const regions = (typeof inputs.regions_array === 'string' 
    ? JSON.parse(inputs.regions_array) 
    : inputs.regions_array) as any[];

  const subscriptions = (typeof inputs.subscriptions_array === 'string' 
    ? JSON.parse(inputs.subscriptions_array) 
    : inputs.subscriptions_array) as any[];

  return { regions, subscriptions };
};

export const code = async (inputs) => {
  return inputs.subscriptions && inputs.subscriptions.length > 3;
};

export const code = async (inputs) => {
  const prices = inputs.lastDaysPrices;

  if (!prices || prices.length === 0) {
    return { average: 0, currency: null };
  }

  const total = prices.reduce((sum, [price]) => sum + price, 0);
  const average = total / prices.length;

  return {
    average,
  };
};

export const code = async (inputs) => {
  const rawItems = Array.isArray(inputs.items) ? inputs.items : [];

  const ids = rawItems
    .map((item) => {
      if (!item) return null;

      if (typeof item === "string") {
        try {
          return JSON.parse(item)?.id || null;
        } catch {
          return null;
        }
      }

      if (typeof item === "object") {
        return item.id || null;
      }

      return null;
    })
    .filter(Boolean);

  return ids.map((id) => `"${id}"`).join(", ");
};

export const code = async (inputs) => {
  const costs = Array.isArray(inputs.costs) ? inputs.costs : [];
  const items = Array.isArray(inputs.items) ? inputs.items : [];

  const normalizeId = (value) => String(value || "").toLowerCase();

  const regionByResourceId = {};

  for (const rawItem of items) {
    if (!rawItem) continue;

    let item = rawItem;

    if (typeof rawItem === "string") {
      try {
        item = JSON.parse(rawItem);
      } catch {
        continue;
      }
    }

    if (!item || typeof item !== "object" || !item.id) continue;

    regionByResourceId[normalizeId(item.id)] = item.region || null;
  }

  const grouped = {};

  for (const [cost, date, resourceId, currency] of costs) {
    const normalizedResourceId = normalizeId(resourceId);

    if (!grouped[normalizedResourceId]) {
      grouped[normalizedResourceId] = {
        resourceId,
        currency,
        region: regionByResourceId[normalizedResourceId] || null,
        datesWithCosts: []
      };
    }

    grouped[normalizedResourceId].datesWithCosts.push([cost, date]);
  }

  return Object.values(grouped);
};

export const code = async (inputs) => {
  const items = inputs.pricingItems || [];

  const today = new Date();
  const dateKey = Number(
    `${today.getUTCFullYear()}${String(today.getUTCMonth() + 1).padStart(2, "0")}${String(today.getUTCDate()).padStart(2, "0")}`
  );

  return items
    .map(item => {
      const parsedItem = typeof item === "string" ? JSON.parse(item) : item;

      return {
        resourceId: parsedItem.resourceId,
        currency: parsedItem.currency || "USD",
        region: parsedItem.region,
        datesWithCosts: [
          [
            parsedItem.dailyPricing || 0,
            dateKey
          ]
        ]
      };
    })
    .filter(item => item.resourceId);
};

export const code = async (inputs) => {
  const rawList = Array.isArray(inputs.allPlans) ? inputs.allPlans : [];

  const parseNumber = (v, def) => {
    if (typeof v === "number") return Number.isFinite(v) ? v : def;
    if (typeof v === "string" && v.trim() !== "") {
      const n = Number(v);
      return Number.isFinite(n) ? n : def;
    }
    return def;
  };

  const maxAppsPerPlan = parseNumber(inputs.maxAppsPerPlan, 9999);
  const maxPlanUtilizationPct = parseNumber(inputs.maxPlanUtilization, 90);
  const maxUtilFrac = maxPlanUtilizationPct / 100;
  const allowCrossAse =
    inputs.shouldReshuffleBetweenInstances === true ||
    String(inputs.shouldReshuffleBetweenInstances).toLowerCase() === "true";

  const EPS = 1e-9;

  const hasObjectValues = (obj) =>
    !!obj &&
    typeof obj === "object" &&
    !Array.isArray(obj) &&
    Object.keys(obj).length > 0;

  const hasAppIdentity = (app) =>
    !!(
      app &&
      typeof app === "object" &&
      (app.id || app.name || app.resourceGroup)
    );

  // --- Parse and de-duplicate items ---
  const items = [];
  const seen = new Set();

  for (const entry of rawList) {
    if (!entry) continue;

    let obj = entry;
    if (typeof entry === "string") {
      try {
        obj = JSON.parse(entry);
      } catch {
        continue;
      }
    }

    if (!obj || typeof obj !== "object") continue;

    const planId =
      obj.plan?.id || obj.plan?.name || JSON.stringify(obj.plan || {});
    const appKey =
      obj.app?.id ||
      obj.app?.name ||
      (hasObjectValues(obj.app) ? JSON.stringify(obj.app) : "__no_app__");

    const key = `${appKey}::${planId}`;
    if (seen.has(key)) continue;
    seen.add(key);
    items.push(obj);
  }

  if (items.length === 0) {
    return {
      parameters: {
        maxAppsPerPlan,
        maxPlanUtilizationPct,
        allowCrossAse,
      },
      moves: [],
      plans: [],
      plansToDecommission: [],
      ases: [],
      asesToDecommission: [],
      info: "No plan/app metric items provided.",
    };
  }

  // --- Build plan map with aggregated app loads ---
  const SECONDS_PER_BUCKET = 3600; // PT1H
  const planMap = new Map();

  const ensurePlan = (item) => {
    const plan = item.plan || {};
    const app = item.app || {};
    const ase = item.ase || {};

    const planId = plan.id || app.planId;
    if (!planId) return null;

    let p = planMap.get(planId);
    if (!p) {
      const instances = parseNumber(plan.instances, 1);
      const workerCores = parseNumber(plan.workerCores, 1);
      const workerRamMB = parseNumber(plan.workerRamMB, 1024);

      const region = ase.location || app.location || null;
      const skuName = plan.skuName || (plan.sku && plan.sku.name) || null;

      let os = null;
      if (plan.os && typeof plan.os === "string") {
        os = plan.os.toLowerCase();
      } else if (app.os && typeof app.os === "string") {
        os = app.os.toLowerCase();
      }

      p = {
        id: planId,
        name: plan.name || null,
        resourceGroup: plan.resourceGroup || null,
        aseId: ase.id || app.aseId || null,
        aseName: ase.name || null,
        aseResourceGroup: ase.resourceGroup || null,
        region,
        os,
        skuName,
        instances,
        workerCores,
        workerRamMB,
        apps: [],
        cpuDemand: 0,
        memDemandMB: 0,
        fullCpuCap: 0,
        fullMemCapMB: 0,
        allowedCpuCap: 0,
        allowedMemCapMB: 0,
        utilCpu: 0,
        utilMem: 0,
        util: 0,
        groupKey: null,
        decommissioned: false,
        isIdle: false,
      };
      planMap.set(planId, p);
    }
    return p;
  };

  for (const item of items) {
    const p = ensurePlan(item);
    if (!p) continue;

    const metrics = item.metrics || {};
    const cpuMaxSec = parseNumber(metrics.cpu?.maxSecondsPerBucket, 0) || 0;

    const memMaxMB =
      parseNumber(metrics.memory?.maxMB, null) ??
      (metrics.memory && metrics.memory.maxBytes
        ? metrics.memory.maxBytes / (1024 * 1024)
        : 0);

    const app = item.app || {};
    const appIdentity = hasAppIdentity(app);
    const appHasActivity = cpuMaxSec > EPS || memMaxMB > EPS;
    const shouldCountAsApp = appIdentity || appHasActivity;

    if (!shouldCountAsApp) {
      continue;
    }

    const appObj = {
      id: app.id || app.name || `unknown-app-${p.id}-${p.apps.length + 1}`,
      name: app.name || app.id || "unknown-app",
      resourceGroup: app.resourceGroup || null,
      cpuDemand: cpuMaxSec,
      memDemandMB: memMaxMB,
      original: item,
    };

    p.apps.push(appObj);
    p.cpuDemand += cpuMaxSec;
    p.memDemandMB += memMaxMB;
  }

  // --- Compute capacity & utilization per plan ---
  const computePlanCapacityAndUtil = (plan) => {
    const fullCpuCap = plan.instances * plan.workerCores * SECONDS_PER_BUCKET;
    const fullMemCapMB = plan.instances * plan.workerRamMB;

    plan.fullCpuCap = fullCpuCap;
    plan.fullMemCapMB = fullMemCapMB;

    plan.allowedCpuCap = fullCpuCap * maxUtilFrac;
    plan.allowedMemCapMB = fullMemCapMB * maxUtilFrac;

    plan.utilCpu = fullCpuCap > 0 ? plan.cpuDemand / fullCpuCap : 0;
    plan.utilMem = fullMemCapMB > 0 ? plan.memDemandMB / fullMemCapMB : 0;
    plan.util = Math.max(plan.utilCpu, plan.utilMem);

    plan.isIdle = plan.cpuDemand <= EPS && plan.memDemandMB <= EPS;

    const region = plan.region || "unknown-region";
    const os = plan.os || "unknown-os";
    const sku = plan.skuName || "unknown-sku";
    plan.groupKey = `${region}|${os}|${sku}`;
  };

  for (const plan of planMap.values()) {
    computePlanCapacityAndUtil(plan);
  }

  // --- Group plans by compatibility (region + OS + SKU) ---
  const groupMap = new Map();
  for (const plan of planMap.values()) {
    const key = plan.groupKey;
    if (!groupMap.has(key)) groupMap.set(key, []);
    groupMap.get(key).push(plan);
  }

  const moves = [];

  // --- Try to decommission underutilized plans within each group ---
  for (const [groupKey, groupPlans] of groupMap.entries()) {
    if (!groupPlans || groupPlans.length <= 1) continue;

    const sortedSources = [...groupPlans].sort(
      (a, b) => (a.util || 0) - (b.util || 0)
    );

    for (const source of sortedSources) {
      if (source.decommissioned) continue;

      if (!source.apps || source.apps.length === 0) {
        source.decommissioned = true;
        continue;
      }

      const candidateTargets = groupPlans.filter((p) => {
        if (p.decommissioned) return false;
        if (p.id === source.id) return false;
        if (!allowCrossAse && p.aseId !== source.aseId) return false;
        return true;
      });

      if (candidateTargets.length === 0) continue;

      const simStates = new Map();
      for (const p of groupPlans) {
        if (p.decommissioned) continue;
        simStates.set(p.id, {
          cpuDemand: p.cpuDemand,
          memDemandMB: p.memDemandMB,
          appCount: p.apps.length,
        });
      }

      const tentativeMoves = [];
      let failed = false;

      for (const app of source.apps) {
        let bestTarget = null;
        let bestNewUtil = -1;

        for (const target of candidateTargets) {
          const st = simStates.get(target.id);
          if (!st) continue;

          const newAppCount = st.appCount + 1;
          if (newAppCount > maxAppsPerPlan) continue;

          const newCpuDemand = st.cpuDemand + app.cpuDemand;
          const newMemDemandMB = st.memDemandMB + app.memDemandMB;

          if (
            target.allowedCpuCap > 0 &&
            newCpuDemand > target.allowedCpuCap + EPS
          ) {
            continue;
          }

          if (
            target.allowedMemCapMB > 0 &&
            newMemDemandMB > target.allowedMemCapMB + EPS
          ) {
            continue;
          }

          const newUtilCpu =
            target.fullCpuCap > 0 ? newCpuDemand / target.fullCpuCap : 0;
          const newUtilMem =
            target.fullMemCapMB > 0 ? newMemDemandMB / target.fullMemCapMB : 0;
          const newUtil = Math.max(newUtilCpu, newUtilMem);

          if (newUtil > maxUtilFrac + EPS) continue;

          if (newUtil > bestNewUtil) {
            bestNewUtil = newUtil;
            bestTarget = target;
          }
        }

        if (!bestTarget) {
          failed = true;
          break;
        }

        const st = simStates.get(bestTarget.id);
        st.cpuDemand += app.cpuDemand;
        st.memDemandMB += app.memDemandMB;
        st.appCount += 1;

        tentativeMoves.push({
          app,
          fromPlanId: source.id,
          toPlanId: bestTarget.id,
          newCpuDemand: st.cpuDemand,
          newMemDemandMB: st.memDemandMB,
          newUtil: bestNewUtil,
          targetPlan: bestTarget,
        });
      }

      if (failed || tentativeMoves.length !== source.apps.length) {
        continue;
      }

      for (const m of tentativeMoves) {
        const fromPlan = planMap.get(m.fromPlanId);
        const toPlan = m.targetPlan;
        if (!fromPlan || !toPlan) continue;

        fromPlan.apps = fromPlan.apps.filter((a) => a.id !== m.app.id);
        fromPlan.cpuDemand -= m.app.cpuDemand;
        fromPlan.memDemandMB -= m.app.memDemandMB;

        if (fromPlan.cpuDemand < 0) fromPlan.cpuDemand = 0;
        if (fromPlan.memDemandMB < 0) fromPlan.memDemandMB = 0;

        toPlan.apps.push(m.app);
        toPlan.cpuDemand += m.app.cpuDemand;
        toPlan.memDemandMB += m.app.memDemandMB;

        computePlanCapacityAndUtil(fromPlan);
        computePlanCapacityAndUtil(toPlan);

        const isCrossAse =
          fromPlan.aseId && toPlan.aseId && fromPlan.aseId !== toPlan.aseId;

        moves.push({
          appId: m.app.id,
          appName: m.app.name,
          fromPlanId: fromPlan.id,
          fromPlanName: fromPlan.name,
          fromPlanResourceGroup: fromPlan.resourceGroup,
          fromAseId: fromPlan.aseId,
          fromAseName: fromPlan.aseName,
          toPlanId: toPlan.id,
          toPlanName: toPlan.name,
          toPlanResourceGroup: toPlan.resourceGroup,
          toAseId: toPlan.aseId,
          toAseName: toPlan.aseName,
          isCrossAse,
          cpuDemandSeconds: m.app.cpuDemand,
          memDemandMB: m.app.memDemandMB,
          targetUtilAfter: m.newUtil,
          groupKey,
          description: `Move ${m.app.name} from ASE ${fromPlan.aseName}; plan ${fromPlan.name} to ASE ${toPlan.aseName}; plan ${toPlan.name}`,
        });
      }

      if (!source.apps || source.apps.length === 0) {
        source.decommissioned = true;
      }
    }
  }

  const planResults = [];
  for (const plan of planMap.values()) {
    computePlanCapacityAndUtil(plan);

    if (plan.apps.length === 0 || plan.isIdle) {
      plan.decommissioned = true;
    }

    planResults.push({
      id: plan.id,
      name: plan.name,
      resourceGroup: plan.resourceGroup,
      aseId: plan.aseId,
      aseName: plan.aseName,
      aseResourceGroup: plan.aseResourceGroup,
      region: plan.region,
      os: plan.os,
      skuName: plan.skuName,
      instances: plan.instances,
      workerCores: plan.workerCores,
      workerRamMB: plan.workerRamMB,
      appCount: plan.apps.length,
      cpuDemandSeconds: plan.cpuDemand,
      memDemandMB: plan.memDemandMB,
      cpuUtil: plan.utilCpu,
      memUtil: plan.utilMem,
      maxUtil: plan.util,
      maxPlanUtilizationPct,
      isIdle: plan.isIdle,
      decommissioned: !!plan.decommissioned,
    });
  }

  const aseMap = new Map();
  for (const p of planResults) {
    const aseId = p.aseId || "unknown-ase";
    let ase = aseMap.get(aseId);
    if (!ase) {
      ase = {
        aseId,
        aseName: p.aseName || null,
        resourceGroup: p.aseResourceGroup || null,
        region: p.region || null,
        plans: [],
        totalApps: 0,
        totalCpuDemandSeconds: 0,
        totalMemDemandMB: 0,
        isIdle: true,
      };
      aseMap.set(aseId, ase);
    }

    ase.plans.push(p);
    ase.totalApps += p.appCount;
    ase.totalCpuDemandSeconds += p.cpuDemandSeconds;
    ase.totalMemDemandMB += p.memDemandMB;

    if (!p.isIdle) {
      ase.isIdle = false;
    }
  }

  const ases = Array.from(aseMap.values());

  const asesToDecommission = ases
    .filter(
      (ase) =>
        ase.plans.length > 0 &&
        ase.plans.every((p) => p.decommissioned || p.isIdle || p.appCount === 0)
    )
    .map((ase) => ({
      aseId: ase.aseId,
      aseName: ase.aseName,
      resourceGroup: ase.resourceGroup,
    }));

  const plansToDecommission = planResults
    .filter((p) => p.decommissioned || p.isIdle || p.appCount === 0)
    .map((p) => ({
      id: p.id,
      name: p.name,
      aseId: p.aseId,
      aseName: p.aseName,
      resourceGroup: p.resourceGroup,
      region: p.region
    }));

  return {
    parameters: {
      maxAppsPerPlan,
      maxPlanUtilizationPct,
      allowCrossAse,
    },
    moves,
    plans: planResults,
    plansToDecommission,
    ases,
    asesToDecommission,
  };
};

export const code = async (inputs) => {
