export const code = async (inputs) => {
  const { appServicePlan, priceList } = inputs;

  const items = Array.isArray(priceList)
    ? priceList
    : Array.isArray(priceList?.Items)
      ? priceList.Items
      : [];

  const resourceId =
    appServicePlan?.id ||
    appServicePlan?.resourceMetadata?.resourceId ||
    null;

  const sku = appServicePlan?.sku || {};
  const skuName = sku.name || sku.size || null;

  if (!skuName) {
    return {
      resourceId,
      dailyPricing: 0,
      currency: "USD"
    };
  }

  const normalize = (value) =>
    String(value || "")
      .toLowerCase()
      .replace(/[_-]/g, "")
      .replace(/\s+/g, "")
      .replace(/app$/g, "")
      .trim();

  const expectedSku = normalize(skuName);

  const kind = String(appServicePlan?.kind || appServicePlan?.properties?.kind || "").toLowerCase();

  const isLinux =
    kind.includes("linux") ||
    appServicePlan?.reserved === true ||
    appServicePlan?.properties?.reserved === true;

  const tier = String(sku.tier || appServicePlan?.properties?.workerTierName || "").toLowerCase();

  const isIsolatedPlan =
    tier.includes("isolated") ||
    Boolean(appServicePlan?.properties?.hostingEnvironmentId) ||
    Boolean(appServicePlan?.properties?.hostingEnvironmentProfile);

  const priceItem = items.find((p) => {
    if (p.type !== "Consumption") return false;
    if (p.serviceName !== "Azure App Service") return false;
    if (p.unitOfMeasure !== "1 Hour") return false;

    const priceSku = normalize(p.skuName);
    const meterName = normalize(p.meterName);
    const armSkuName = normalize(p.armSkuName);
    const productName = String(p.productName || "").toLowerCase();

    const skuMatches =
      priceSku === expectedSku ||
      meterName === expectedSku ||
      meterName.startsWith(expectedSku) ||
      armSkuName.includes(expectedSku);

    if (!skuMatches) return false;

    const isPriceLinux =
      productName.includes("linux") ||
      String(p.armSkuName || "").toLowerCase().includes("linux");

    if (isLinux !== isPriceLinux) return false;

    if (productName.includes("isolated") !== isIsolatedPlan) {
      return false;
    }

    if (
      productName.includes("ssl") ||
      productName.includes("domain") ||
      productName.includes("stamp") ||
      p.skuName === "Front End"
    ) {
      return false;
    }

    return true;
  });

  if (!priceItem || typeof priceItem.retailPrice !== "number") {
    return {
      resourceId,
      dailyPricing: 0,
      currency: "USD"
    };
  }

  const workerCount = Number(
    appServicePlan?.sku?.capacity ||
    appServicePlan?.properties?.numberOfWorkers ||
    appServicePlan?.numberOfWorkers ||
    1
  );

  return {
    resourceId,
    dailyPricing: priceItem.retailPrice * 24 * workerCount,
    currency: priceItem.currencyCode || "USD",
    region: appServicePlan.location
  };
};

export const code = async (inputs) => {
  const parseMaybeJson = (value) => {
    if (typeof value !== "string") return value;

    try {
      return JSON.parse(value);
    } catch {
      return value;
    }
  };

  const normalizeId = (value) =>
    String(value || "")
      .trim()
      .replace(/^\/+/, "")
      .replace(/\s+/g, "")
      .toLowerCase();

  const rawItems = parseMaybeJson(inputs?.items);
  const items = Array.isArray(rawItems) ? rawItems : [];

  const resourceId = normalizeId(inputs?.resourceId);

  return items.filter((rawItem) => {
    const item = parseMaybeJson(rawItem);

    return (
      normalizeId(item?.hostingEnvironmentProfile?.id) === resourceId
    );
  });
};

