export const code = async (inputs) => {
  const raw = inputs?.multisize;
  const rawItems = inputs?.items;

  if (raw == null) {
    return { error: "multisize not provided" };
  }

  if (rawItems == null) {
    return { error: "items not provided" };
  }

  const value = String(raw).trim();

  const parts = value
    .split(">")
    .map((p) => p.trim())
    .filter(Boolean);

  const cleanMultiSize = parts.length > 0 ? parts[parts.length - 1] : "";

  let items = rawItems;

  if (typeof rawItems === "string") {
    try {
      items = JSON.parse(rawItems);
    } catch {
      return { error: "items is not valid JSON" };
    }
  }

  if (!Array.isArray(items)) {
    return { error: "items must be an array" };
  }

  const matchedItem = items.find((item) => {
    if (Array.isArray(item)) {
      return String(item[0] || "").trim() === cleanMultiSize;
    }

    return String(item?.name || item?.vmSize || item?.size || "").trim() === cleanMultiSize;
  });

  if (!matchedItem) {
    return {
      error: "matching size not found",
      cleanMultiSize,
    };
  }

  return matchedItem;
};

export const code = async (inputs) => {
  const { cpuTime, memoryWorkingSet, webapp, currentPlan, currentASE, numberOfProcessors, memorySize } = inputs;

  const getMax = (metric) => {
    const ts = metric?.value?.[0]?.timeseries?.[0]?.data ?? [];
    let max = 0;
    for (const p of ts) {
      if (typeof p.maximum === "number" && p.maximum > max) max = p.maximum;
    }
    return max;
  };

  const cpuMaxSeconds = getMax(cpuTime);
  const memMaxBytes = getMax(memoryWorkingSet);

  const memMaxMB = memMaxBytes / (1024 * 1024);
  const planInstances = currentPlan?.sku?.capacity ?? currentPlan?.numberOfWorkers ?? 1;
  const workerCores = numberOfProcessors;
  const workerRamMB = memorySize;

  const cpuCapacityPerDay = planInstances * workerCores * 86400;
  const memCapacityBytes = planInstances * workerRamMB * 1024 * 1024;

  const cpuShare = cpuCapacityPerDay > 0 ? cpuMaxSeconds / cpuCapacityPerDay : null;
  const memShare = memCapacityBytes > 0 ? memMaxBytes / memCapacityBytes : null;

  const cpuPercent = cpuShare != null ? cpuShare * 100 : null;
  const memPercent = memShare != null ? memShare * 100 : null;

  const loadScore = Math.max(cpuShare ?? 0, memShare ?? 0);

  return {
    app: {
      id: webapp?.id,
      name: webapp?.name,
      resourceGroup: webapp?.resourceGroup,
      location: webapp?.location,
      planId: webapp?.appServicePlanId,
      aseId: webapp?.hostingEnvironmentProfile?.id,
    },
    plan: {
      id: currentPlan?.id,
      name: currentPlan?.name,
      resourceGroup: currentPlan?.resourceGroup,
      instances: planInstances,
