export const code = async (inputs) => {
  const raw = inputs?.multisize;
  const rawItems = inputs?.items;

  if (raw == null) {
    return { error: "multisize not provided" };
  }

  if (rawItems == null) {
    return { error: "items not provided" };
  }

  const value = String(raw).trim();

  const parts = value
    .split(">")
    .map((p) => p.trim())
    .filter(Boolean);

  const cleanMultiSize = parts.length > 0 ? parts[parts.length - 1] : "";

  let items = rawItems;

  if (typeof rawItems === "string") {
    try {
      items = JSON.parse(rawItems);
    } catch {
      return { error: "items is not valid JSON" };
    }
  }

  if (!Array.isArray(items)) {
    return { error: "items must be an array" };
  }

  const matchedItem = items.find((item) => {
    if (Array.isArray(item)) {
      return String(item[0] || "").trim() === cleanMultiSize;
    }

    return String(item?.name || item?.vmSize || item?.size || "").trim() === cleanMultiSize;
  });

  if (!matchedItem) {
    return {
      error: "matching size not found",
      cleanMultiSize,
    };
  }

  return matchedItem;
};

export const code = async (inputs) => {
  const { metrics, webapp, currentPlan, currentASE, numberOfProcessors, memorySize } = inputs;

  const parsedMetrics =
    typeof metrics === "string"
      ? JSON.parse(metrics)
      : metrics;

  const metricItems = Array.isArray(parsedMetrics?.value)
    ? parsedMetrics.value
    : Array.isArray(parsedMetrics)
      ? parsedMetrics
      : [];

  const findMetric = (metricName) => {
    const expected = String(metricName || "").toLowerCase();

    return metricItems.find((metric) => {
      const value = String(metric?.name?.value || "").toLowerCase();
      const localizedValue = String(metric?.name?.localizedValue || "").toLowerCase();
      const id = String(metric?.id || "").toLowerCase();

      return (
        value === expected ||
        localizedValue === expected ||
        id.endsWith(`/metrics/${expected}`)
      );
    });
  };

  const getMax = (metric) => {
    const timeseries = Array.isArray(metric?.timeseries)
      ? metric.timeseries
      : [];

    let max = 0;

    for (const series of timeseries) {
      const data = Array.isArray(series?.data) ? series.data : [];

      for (const p of data) {
        if (typeof p.maximum === "number" && p.maximum > max) {
          max = p.maximum;
        }
      }
    }

    return max;
  };

  const cpuTimeMetric = findMetric("CpuTime");
  const memoryWorkingSetMetric = findMetric("MemoryWorkingSet");

  const cpuMaxSeconds = getMax(cpuTimeMetric);
  const memMaxBytes = getMax(memoryWorkingSetMetric);

  const memMaxMB = memMaxBytes / (1024 * 1024);
  const planInstances = currentPlan?.sku?.capacity ?? currentPlan?.numberOfWorkers ?? 1;
  const workerCores = numberOfProcessors;
  const workerRamMB = memorySize;

  const cpuCapacityPerDay = planInstances * workerCores * 86400;
  const memCapacityBytes = planInstances * workerRamMB * 1024 * 1024;

  const cpuShare = cpuCapacityPerDay > 0 ? cpuMaxSeconds / cpuCapacityPerDay : null;
  const memShare = memCapacityBytes > 0 ? memMaxBytes / memCapacityBytes : null;

  const cpuPercent = cpuShare != null ? cpuShare * 100 : null;
  const memPercent = memShare != null ? memShare * 100 : null;

  const loadScore = Math.max(cpuShare ?? 0, memShare ?? 0);

  return {
    app: {
      id: webapp?.id,
      name: webapp?.name,
      resourceGroup: webapp?.resourceGroup,
      location: webapp?.location,
      planId: webapp?.appServicePlanId,
      aseId: webapp?.hostingEnvironmentProfile?.id,
    },
    plan: {
      id: currentPlan?.id,
      name: currentPlan?.name,
      resourceGroup: currentPlan?.resourceGroup,
      instances: planInstances,
      workerCores,
      workerRamMB,
    },
    ase: {
      id: currentASE?.id,
      name: currentASE?.name,
      resourceGroup: currentASE?.resourceGroup,
      location: currentASE?.location,
      multiSize: currentASE?.multiSize,
    },
    metrics: {
      cpu: {
        metricFound: !!cpuTimeMetric,
        maxSecondsPerBucket: cpuMaxSeconds,
        capacitySecondsPerDay: cpuCapacityPerDay,
        share: cpuShare,
        percent: cpuPercent,
      },
      memory: {
        metricFound: !!memoryWorkingSetMetric,
        maxBytes: memMaxBytes,
        maxMB: memMaxMB,
        capacityBytes: memCapacityBytes,
        share: memShare,
        percent: memPercent,
      },
      loadScore,
    },
    summary: {
      text: `App ${webapp?.name} uses ~${cpuPercent?.toFixed?.(4)}% CPU and ~${memPercent?.toFixed?.(4)}% RAM of plan ${currentPlan?.name} in ASE ${currentASE?.name}.`,
    },
  };
};
